(window.webpackJsonp=window.webpackJsonp||[]).push([[307],{934:function(n,e){n.exports="\x3c!-- \ntitle: 40-NodeJS入门\nsort: \n--\x3e \n\n## 全局对象\n\n> Node 没有 `document` 和 `window` 等全局对象。\n>\n> Node 的全局对象是 `process`。\n\n### process\n\n- `pid`：进程编号\n- `env`：系统环境变量\n- `argv`：命令行执行此脚本时的输入参数\n- `platform`：当前操作系统的平台\n\n### Buffer\n\n> 处理二进制数据\n\n```js\nconst buf = Buffer.from('fzf404', 'ascii');\n<Buffer 66 7a 66 34 30 34>\nbuf.toString('hex')\nbuf.toString('base64')\n```\n\n## 模块机制\n\n- 编写模块\n\n```js\nconst os = require('os');\n\nfunction printProgramInfo() {\n\tconsole.log('当前用户', os.userInfo().username);\n\tconsole.log('当前进程 ID', process.pid);\n\tconsole.log('当前脚本路径', __filename);\n}\n\nfunction getCurrentTime() {\n\tconst time = new Date();\n\treturn time.toLocaleString();\n}\n\n// 导出函数\nmodule.exports.printProgramInfo = printProgramInfo;\nmodule.exports.getCurrentTime = getCurrentTime;      \n```\n\n- 导入模块\n\n```js\nconst { printProgramInfo, getCurrentTime } = require('./demo')\nprintProgramInfo()\ngetCurrentTime()\n```\n\n## 命令行\n\n> 使用npm安装依赖\n\n### commander\n\n> `yarn add commander`\n\n```js\nconst { Command } = require('commander');\nconst program = new Command();\n\n// 配置选项\nprogram\n  .option('-d, --debug', 'output extra debugging')\n  // 选项 延迟输出 默认值\n  .option('-t, --time <number>', 'delay time', 10)\n  .option('-m, --message <string>', 'output message', 'Hello Command');\n\nprogram.parse(process.argv);\n\n// 获取选项参数\nconst options = program.opts();\n// debug选项激活则打印所有参数\nif (options.debug) console.log(options);\n\n// 延时打印\nsetTimeout(() => {\n  console.log(options.message);\n}, options.time);\n```\n\n## 监听与事件\n\n### event\n\n> 事件触发与事件监听器功能\n\n```js\nconst {EventEmitter} = require('events');\n\nconst emitter = new EventEmitter();\n\n// 监听 connect 事件，注册回调函数\nemitter.on('connect', username => {\n  console.log(`${username} 已连接`);\n});\n\n// 触发 connect 事件\nemitter.emit('connect', 'fzf404');\n```\n\n## 服务\n\n```js\nlet http = require('http');\nlet querystring = require('querystring');\n\n// 数据\nlet my_result = [{\n  date: '2016-05-02',\n  name: '王小虎',\n  address: '上海市普陀区金沙江路 1518 弄'\n}, {\n  date: '2016-05-04',\n  name: '王小虎',\n  address: '上海市普陀区金沙江路 1517 弄'\n}, {\n  date: '2016-05-01',\n  name: '王小虎',\n  address: '上海市普陀区金沙江路 1519 弄'\n}, {\n  date: '2016-05-03',\n  name: '王小虎',\n  address: '上海市普陀区金沙江路 1516 弄'\n}]\n\n// 创建服务\nlet server = http.createServer((req, res) => {\n  // 获取form-data的内容\n  let post = '';\n  req.on('data', function (chunk) {\n    post += chunk;\n  });\n\n  req.on('end', function () {\n    // 响应头\n    res.writeHead(200, {\n      'Content-Type': 'application/json; charset=utf-8'\n    })\n    // 字节流转换成字符串\n    post = querystring.parse(post);\n    console.log('post-data:', post);\n    // 返回数据\n    if (post) {\n      let result = {\n        code: 200,\n        msg: \"获取成功\"\n        data: my_result\n      }\n      res.end(JSON.stringify(result));\n    } else {\n      let result = {\n        code: '0',\n        msg: '没有接受到数据'\n      }\n      res.end(JSON.stringify(result));\n    }\n  });\n});\n// 开启服务\nserver.listen(8886)\n```\n\n"}}]);